package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.Reader;
import java.io.StringReader;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.MockedConstruction;
import org.mockito.Mockito;

public class CSVFormatTest {

    private CSVFormat csvFormat;

    @BeforeEach
    public void setUp() {
        csvFormat = CSVFormat.DEFAULT;
    }

    @Test
    public void testParse_withValidReader_invokesCSVParserConstructor() throws IOException {
        Reader reader = new StringReader("a,b,c\n1,2,3");

        try (MockedConstruction<CSVParser> mocked = Mockito.mockConstruction(CSVParser.class,
                (mock, context) -> {
                    // no-op
                })) {

            CSVParser parser = csvFormat.parse(reader);

            assertNotNull(parser);
            assertEquals(1, mocked.constructed().size());
            CSVParser constructed = mocked.constructed().get(0);
            assertSame(constructed, parser);
        }
    }

    @Test
    public void testParse_withNullReader_throwsNullPointerException() {
        assertThrows(NullPointerException.class, () -> {
            csvFormat.parse(null);
        });
    }
}
